import axios from "axios";

const apiClient = axios.create({
    baseURL: "http://localhost:3000/api",
    headers: { "Content-Type": "application/json" }
});

apiClient.interceptors.request.use(config => {
    const token = localStorage.getItem('token');
    if (token) config.headers.Authorization = token;
    return config;
});

export const api = {
    createProduct: async (product) => (await apiClient.post("/products", product)).data,
    getProducts: async () => (await apiClient.get("/products")).data,
    updateProduct: async (id, product) => (await apiClient.patch(`/products/${id}`, product)).data,
    deleteProduct: async (id) => await apiClient.delete(`/products/${id}`),

    createOrder: async (order) => (await apiClient.post("/orders", order)).data,
    getOrders: async () => (await apiClient.get("/orders")).data,
    updateOrder: async (id, order) => (await apiClient.patch(`/orders/${id}`, order)).data,
    deleteOrder: async (id) => await apiClient.delete(`/orders/${id}`),

    register: async (data) => (await apiClient.post("/register", data)).data,
    login: async (data) => (await apiClient.post("/login", data)).data
};
